using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

using System.ComponentModel.DataAnnotations;

namespace TicketClassifier.Models;

public class TicketRequest
{
    [Required]
    public string Subject { get; set; } = string.Empty;

    [Required]
    public string Description { get; set; } = string.Empty;

    [Range(1, 3)]
    public int Priority { get; set; }
}

public class PredictionResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

public class EvaluationResponse
{
    public double MacroAccuracy { get; set; }
    public double MicroAccuracy { get; set; }
    public double LogLoss { get; set; }
    public double LogLossReduction { get; set; }
    public PerClassMetrics[] PerClassMetrics { get; set; } = [];
}

public class PerClassMetrics
{
    public string Class { get; set; } = string.Empty;
    public double Precision { get; set; }
    public double Recall { get; set; }
    public double F1Score { get; set; }
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketClassifierService
{
    private readonly MLContext _mlContext;
    private readonly ITransformer _model;
    private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
    private readonly string[] _categoryLabels;
    private readonly EvaluationResponse _evaluationMetrics;

    public TicketClassifierService(string dataPath)
    {
        _mlContext = new MLContext(seed: 42);

        var dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var pipeline = _mlContext.Transforms.Conversion.MapValueToKey("Label", nameof(TicketData.Category))
            .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
            .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features", "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .AppendCacheCheckpoint(_mlContext)
            .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

        // With only 6 rows, cross-validation gives a more honest estimate than a single split
        var cvResults = _mlContext.MulticlassClassification.CrossValidate(dataView, pipeline, numberOfFolds: 3, labelColumnName: "Label");

        _evaluationMetrics = AggregateCvMetrics(cvResults);

        // Train final model on all data
        _model = pipeline.Fit(dataView);
        _predictionEngine = _mlContext.Model.CreatePredictionEngine<TicketData, TicketPrediction>(_model);

        // Extract ordered label names so we can map Score[] indices to categories
        var labelBuffer = new VBuffer<ReadOnlyMemory<char>>();
        _model.GetOutputSchema(dataView.Schema)["Score"]
            .GetSlotNames(ref labelBuffer);
        _categoryLabels = labelBuffer.DenseValues().Select(v => v.ToString()).ToArray();
    }

    public (TicketPrediction Prediction, Dictionary<string, float> Confidence) Predict(TicketData ticket)
    {
        var prediction = _predictionEngine.Predict(ticket);
        var confidence = new Dictionary<string, float>();

        for (var i = 0; i < _categoryLabels.Length; i++)
        {
            confidence[_categoryLabels[i]] = prediction.Score[i];
        }

        return (prediction, confidence);
    }

    public EvaluationResponse GetEvaluationMetrics() => _evaluationMetrics;

    private static EvaluationResponse AggregateCvMetrics(
        IReadOnlyList<CrossValidationResult<Microsoft.ML.Data.MulticlassClassificationMetrics>> cvResults)
    {
        return new EvaluationResponse
        {
            MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
            MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
            LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
            LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction),
            PerClassMetrics = Enumerable.Range(0, cvResults[0].Metrics.PerClassLogLoss.Count)
                .Select(i => new PerClassMetrics
                {
                    Class = $"Class{i}",
                    Precision = cvResults.Average(r => i < r.Metrics.ConfusionMatrix.PerClassPrecision.Count
                        ? r.Metrics.ConfusionMatrix.PerClassPrecision[i] : 0),
                    Recall = cvResults.Average(r => i < r.Metrics.ConfusionMatrix.PerClassRecall.Count
                        ? r.Metrics.ConfusionMatrix.PerClassRecall[i] : 0),
                    F1Score = cvResults.Average(r =>
                    {
                        if (i >= r.Metrics.ConfusionMatrix.PerClassPrecision.Count) return 0;
                        var p = r.Metrics.ConfusionMatrix.PerClassPrecision[i];
                        var rec = r.Metrics.ConfusionMatrix.PerClassRecall[i];
                        return (p + rec) > 0 ? 2 * p * rec / (p + rec) : 0;
                    })
                }).ToArray()
        };
    }
}

using Microsoft.AspNetCore.Mvc;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(TicketClassifierService classifier) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult<PredictionResponse> Classify([FromBody] TicketRequest request)
    {
        if (!ModelState.IsValid)
            return BadRequest(ModelState);

        var ticketData = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var (prediction, confidence) = classifier.Predict(ticketData);

        return Ok(new PredictionResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }

    [HttpGet("metrics")]
    public ActionResult<EvaluationResponse> GetMetrics()
    {
        return Ok(classifier.GetEvaluationMetrics());
    }
}

